#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define PI 3.1415926535897932
#define M 2147483647
#define A 1103515245
#define C 12345

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < 0.5)
        return (double)newValue;
    else
        return (double)(newValue + 1);
}

double randu(int * seed, int index) {
    long long num = (long long)A * seed[index] + C;
    seed[index] = (int)(num % M);
    return fabs(seed[index] / ((double)M));
}

double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2.0 * PI * v);
    double rt = -2.0 * log(u);
    return sqrt(rt) * cosine;
}

__kernel void likelihood_kernel(
    __global double * arrayX,
    __global double * arrayY,
    __global double * xj,
    __global double * yj,
    __global double * CDF,
    __global int * ind,
    __global int * objxy,
    __global double * likelihood,
    __global unsigned char * I,
    __global double * u,
    __global double * weights,
    int Nparticles,
    int countOnes,
    int max_size,
    int k,
    int IszY,
    int Nfr,
    __global int * seed,
    __global double * partial_sums,
    __local double * local_sum)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    int local_id = get_local_id(0);
    local_sum[local_id] = 0.0;

    // Update position with noise
    arrayX[x] += 1.0 + 5.0 * randn(seed, x);
    arrayY[x] += -2.0 + 2.0 * randn(seed, x);

    // Calculate indices for neighbors
    for (int y = 0; y < countOnes; y++) {
        int indX = (int)roundDouble(arrayX[x]) + objxy[y * 2 + 1];
        int indY = (int)roundDouble(arrayY[x]) + objxy[y * 2];
        int idx = indX * IszY * Nfr + indY * Nfr + k;
        if (idx >= max_size || idx < 0) idx = 0;
        ind[x * countOnes + y] = idx;
    }

    // Calculate likelihood
    double lik = 0.0;
    for (int y = 0; y < countOnes; y++) {
        int val = I[ind[x * countOnes + y]];
        lik += ((pow((double)(val - 100), 2.0) - pow((double)(val - 228), 2.0)) / 50.0);
    }
    likelihood[x] = lik / ((double)countOnes);

    // Update weights
    weights[x] = weights[x] * exp(likelihood[x]);
    local_sum[local_id] = weights[x];

    // Barrier for local sum
    barrier(CLK_LOCAL_MEM_FENCE);

    // Parallel sum within block (simple reduction)
    for (int s = 1; s < get_local_size(0); s *= 2) {
        if (local_id % (2 * s) == 0) {
            if (local_id + s < get_local_size(0)) {
                local_sum[local_id] += local_sum[local_id + s];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (local_id == 0) {
        partial_sums[x] = local_sum[0];
    }
}

__kernel void sum_kernel(__global double * partial_sums, int Nparticles) {
    int x = get_global_id(0);
    if (x == 0) {
        double total = 0.0;
        for (int i = 0; i < Nparticles; i++) {
            total += partial_sums[i];
        }
        partial_sums[Nparticles] = total;
    }
}

__kernel void normalize_weights_kernel(
    __global double * weights,
    int Nparticles,
    __global double * partial_sums,
    __global double * CDF,
    __global double * u,
    __global int * seed)
{
    int x = get_global_id(0);
    if (x >= Nparticles) return;

    double sumWeights = partial_sums[Nparticles];
    if (sumWeights == 0.0) sumWeights = 1.0;

    weights[x] = weights[x] / sumWeights;

    if (x == 0) {
        CDF[0] = weights[0];
        double u1 = (1.0 / ((double)Nparticles)) * randu(seed, 0);
        for (int i = 0; i < Nparticles; i++) {
            u[i] = u1 + ((double)i / ((double)Nparticles));
        }
    } else {
        CDF[x] = weights[x] + CDF[x - 1];
    }
}

__kernel void find_index_kernel(
    __global double * arrayX,
    __global double * arrayY,
    __global double * CDF,
    __global double * u,
    __global double * xj,
    __global double * yj,
    __global double * weights,
    int Nparticles)
{
    int j = get_global_id(0);
    if (j >= Nparticles) return;

    double value = u[j];
    int index = -1;

    for (int i = 0; i < Nparticles; i++) {
        if (CDF[i] >= value) {
            index = i;
            break;
        }
    }
    if (index == -1) index = Nparticles - 1;

    xj[j] = arrayX[index];
    yj[j] = arrayY[index];

    weights[j] = 1.0 / ((double)Nparticles);

    arrayX[j] = xj[j];
    arrayY[j] = yj[j];
}

